function writeLog(message) {
  console.log(new Date() + ": " + message);
}
writeLog("started");

public void writeLog(String message) {
    System.out.println(new Date() + ": " + message);
}
writeLog("started");

CREATE PROCEDURE WriteLog(IN message VARCHAR(100))
BEGIN
  INSERT INTO logs (message, timestamp) VALUES (message, NOW());
END;
